def gen(rng, size):
    g = rng.choice([2, 3, 4, 5])
    deck = []
    for v in range(rng.randint(1, max(1, size // g))):
        deck += [v] * (g * rng.randint(1, 3))
    if not deck:
        deck = [0, 0]
    return [deck]

