var hasGroupsSizeX = function(deck) {
    const counts = new Map();
    for (const c of deck) counts.set(c, (counts.get(c) || 0) + 1);
    const gcd = (a, b) => b === 0 ? a : gcd(b, a % b);
    let g = 0;
    for (const v of counts.values()) g = gcd(g, v);
    return g >= 2;
};
